import{_ as i,n as a,p as s,Y as t}from"./chunks/framework.KP8KjELV.js";const b=JSON.parse('{"title":"内部实现","description":"","frontmatter":{},"headers":[],"relativePath":"Stack/Git/Tutorial/internal.md","filePath":"Stack/Git/Tutorial/internal.md","lastUpdated":1703840066000}'),e={name:"Stack/Git/Tutorial/internal.md"},h=t('<h1 id="内部实现" tabindex="-1">内部实现 <a class="header-anchor" href="#内部实现" aria-label="Permalink to &quot;内部实现&quot;">​</a></h1><h2 id="git-目录" tabindex="-1">.git 目录 <a class="header-anchor" href="#git-目录" aria-label="Permalink to &quot;.git 目录&quot;">​</a></h2><p>版本管理的所有信息，保存在项目的<code>.git</code>目录之中。如果没有这个目录，Git 就会认为这个仓库没有建立版本管理，必须进行初始化。<code>git init</code>命令的主要作用，就是建立<code>.git</code>目录。</p><p><code>.git/config</code>文件保存仓库的设置。</p><p><code>.git/HEAD</code>文件保存当前工作分支的引用。</p><p><code>.git/hooks</code>目录保存各种事件挂钩的脚本。</p><p><code>.git/objects</code>目录保存文件的内容，格式是二进制<code>blob</code>。</p><h2 id="哈希签名" tabindex="-1">哈希签名 <a class="header-anchor" href="#哈希签名" aria-label="Permalink to &quot;哈希签名&quot;">​</a></h2><p>每次提交的时候，每个文件、每个树节点（目录）和提交本身，都会生成一个40个字符长的 SHA-1 哈希。</p><p>哈希作为文件名，文件本身保留在<code>.git/objects</code>目录之中。</p><h2 id="git-add-命令" tabindex="-1">git add 命令 <a class="header-anchor" href="#git-add-命令" aria-label="Permalink to &quot;git add 命令&quot;">​</a></h2><p><code>git add</code>会将变动的文件写入<code>.git/objects</code>目录。它内部调用的是<code>git hash-object</code>命令,该命令会计算 SHA-1 哈希，并将 blob 文件放入<code>.git/objects</code>目录。</p><div class="language-bash vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang">bash</span><pre class="shiki shiki-themes github-light github-dark vp-code"><code><span class="line"><span style="--shiki-light:#6F42C1;--shiki-dark:#B392F0;">$</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> git</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> hash-object</span><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;"> -w</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> myfile.txt</span></span></code></pre></div><p><code>git cat-file</code>命令可以查看 blob 格式对应的原始文件内容。</p><div class="language-bash vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang">bash</span><pre class="shiki shiki-themes github-light github-dark vp-code"><code><span class="line"><span style="--shiki-light:#6F42C1;--shiki-dark:#B392F0;">$</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> git</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> cat-file</span><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;"> -p</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> e69de29bb2d1d6434b8b29ae775ad8c2e48c5391</span></span></code></pre></div><h2 id="git-commit-命令" tabindex="-1">git commit 命令 <a class="header-anchor" href="#git-commit-命令" aria-label="Permalink to &quot;git commit 命令&quot;">​</a></h2><p><code>git commit</code>命令用于有变动的、并已提交到<code>.git/objects</code>的文件写入历史。</p><p><code>git write-tree</code>为当前仓库创建树节点。</p><div class="language-bash vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang">bash</span><pre class="shiki shiki-themes github-light github-dark vp-code"><code><span class="line"><span style="--shiki-light:#6F42C1;--shiki-dark:#B392F0;">$</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> git</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> write-tree</span></span></code></pre></div><p><code>git commit-tree</code>命令将指定的树节点写入历史。</p><div class="language-bash vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang">bash</span><pre class="shiki shiki-themes github-light github-dark vp-code"><code><span class="line"><span style="--shiki-light:#6F42C1;--shiki-dark:#B392F0;">$</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> echo“first</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> commit”</span><span style="--shiki-light:#D73A49;--shiki-dark:#F97583;">|</span><span style="--shiki-light:#6F42C1;--shiki-dark:#B392F0;"> git</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> commit-tree</span><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;"> \\ </span><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;">6</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;">e9432aeedbad83fbffb7f8aae4a5d1ab50b7fdf</span></span></code></pre></div>',21),d=[h];function o(l,p,c,n,r,k){return a(),s("div",null,d)}const F=i(e,[["render",o]]);export{b as __pageData,F as default};
